    private void jButton13ActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_jButton13ActionPerformed
        // TODO add your handling code here:
        visor.setText("0");
        num1 = (double) 0;
        num2 = (double) 0;
        operador = -1;
    }//GEN-LAST:event_jButton13ActionPerformed

    private void Button1(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_Button1
        // TODO add your handling code here:
        //se o visor for igual a 0 (zero) acrescenta o numero digitado, senão concatene.  
        if (visor.getText().equals("0")) {
            visor.setText("1");
        } else {
            visor.setText(visor.getText() + "1");
        }
        //se o operador for nulo guarde o valor na variavel num1, senão guarde na variavel num2  
        if (operador == -1) {
            num1 = Double.parseDouble(visor.getText());
        } else {
            num2 = Double.parseDouble(visor.getText());
        }
    }//GEN-LAST:event_Button1

