    private void Button0ActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_Button0ActionPerformed
        // TODO add your handling code here:
        //se o visor for igual a 0 (zero) acrescenta o numero digitado, senão concatene.  

        if (visor.getText().equals("0")) {
            visor.setText("0");
        } else {
            visor.setText(visor.getText() + "0");
        }
        //se o operador for nulo guarde o valor na variavel num1, senão guarde na variavel num2  
        if (operador == -1) {
            num1 = Double.parseDouble(visor.getText());
        } else {
            num2 = Double.parseDouble(visor.getText());
        }
    }//GEN-LAST:event_Button0ActionPerformed

    private void somaActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_somaActionPerformed
        // TODO add your handling code here:
        operador = 0;
        visor.setText("0");
    }//GEN-LAST:event_somaActionPerformed

    private void igual(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_igual
        // TODO add your handling code here:
        switch (operador) {
            case 0:
                num1 = num1 + num2;
                visor.setText(String.valueOf(num1));
                operador = -1;
                break;
            case 1:
                num1 = num1 - num2;
                visor.setText(String.valueOf(num1));
                operador = -1;
                break;
            case 2:
                num1 = num1 * num2;
                visor.setText(String.valueOf(num1));
                operador = -1;
                break;
            case 3:
                num1 = num1 / num2;
                visor.setText(String.valueOf(num1));
                operador = -1;
                break;
        }
    }//GEN-LAST:event_igual

